            "items": {
                "type": "string"
            }
        },
        "modules": {
            "type": "array",
            "items": {
                "type": "string"
            }
        },
        "resources": {
            "type": "array",
            "items": {
                "type": "string"
            }
        },
        "skip_compilation": {
            "type": "array",
            "items": {
                "type": "string"
            }
        },
        "experiment": {
            "type": "string"
        }
    },
    "definitions": {}
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "title": "Blockchain Certificates Receipt Schema, Version 1.2",
    "id": "https://w3id.org/blockcerts/schema/1.2/blockchain-receipt-1.2.json",
    "description": "Provides evidence of the certificate on the blockchain, using the chainpoint v2 standard",
    "type": "object",
    "properties": {
        "@context": {
            "type": "string",
            "pattern": "https://w3id.org/chainpoint/v2",
            "description": "This should always be chainpoint v2 JSON LD context"
        },
        "type": {
            "type": "string",
            "pattern": "ChainpointSHA256v2",
            "description": "type of hash. Currently the only supported hash type is SHA256, with chainpoint type ChainpointSHA256v2."
        },
        "targetHash": {
            "type": "string",
            "pattern": "[A-Fa-f0-9]{64}",
            "description": "hash of item being verified. Currently the only supported hash type is SHA256, and the targetHash format is validated accordingly."
        },
        "merkleRoot": {
            "type": "string",
            "pattern": "[A-Fa-f0-9]{64}",
            "description": "Merkle root value -- this is anchored to the blockchain. Currently the only supported hash type is SHA256, and merkleRoot format is validated accordingly."
        },
        "proof": {
            "type": "array",
            "description": "how to walk the Merkle tree from the target item to the Merkle root",
            "items": {
                "type": "object",
                "properties": {
                    "left": {
                        "type": "string",
                        "pattern": "[A-Fa-f0-9]{64}",
                        "description": "value of left neighbor to combine into parent hash. Currently the only supported hash type is SHA256, and this value format is validated accordingly."
                    },
                    "right": {
                        "type": "string",
                        "pattern": "[A-Fa-f0-9]{64}",
                        "description": "value of right neighbor to combine into parent hash. Currently the only supported hash type is SHA256, and this value format is validated accordingly."
                    }
                }
            }
        },
        "anchors": {
            "type": "array",
            "description": "how the proof is anchored to the blockchain",
            "items": {
                "type": "object",
                "properties": {
                    "type": {
                        "type": "string",
                        "pattern": "BTCOpReturn",
                        "description": "type of anchor, e.g. BTCOpReturn. Currently the only supported value is BTCOpReturn."
                    },
                    "sourceId": {
                        "type": "string",
                        "pattern": "[A-Fa-f0-9]{64}",
                        "description": "How to lookup the proof on the blockchain. Currently this is expected to be the (value of the) Bitcoin transaction id, and this value format is validated accordingly"
                    }
                },
                "required": [
                    "sourceId"
                ]
            }
        }
    },
    "required": [
        "@context",
        "targetHash",
        "merkleRoot",
        "proof",
        "anchors"
    ]
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "additionalProperties": false,
    "id": "https://w3id.org/blockcerts/schema/1.2/issuer-id-1.2.json",
    "properties": {
        "email": {
            "_format": "email",
            "description": "Contact address for the individual or organization.",
            "type": "string"
        },
        "id": {
            "_format": "uri",
            "description": "The URL of the issuer's website or homepage",
            "type": "string"
        },
        "image": {
            "description": "Data URI; a base-64 encoded png image of the issuer's image. https://en.wikipedia.org/wiki/Data_URI_scheme",
            "pattern": "data:image/png;base64,",
            "type": "string"
        },
        "introductionURL": {
            "_format": "uri",
            "description": "The URL hosting the issuer's introduction endpoint",
            "type": "string"
        },
        "issuerKeys": {
            "description": "list of issuer keys, listed in descending date order (most recent first). V1.2 change: renamed from issuer_key, added optional invalidated field.",
            "items": {
                "additionalProperties": false,
                "properties": {
                    "date": {
                        "_format": "date-time",
                        "description": "ISO-8601 formatted date time the key was activated.",
                        "type": "string"
                    },
                    "invalidated": {
                        "_format": "date-time",
                        "description": "Optional ISO-8601 formatted date time the key was invalidated.",
                        "type": "string"
                    },
                    "key": {
                        "description": "Bitcoin address (compressed public key, usually 24 characters) that the issuer uses to issue the certificates.",
                        "type": "string"
                    }
                },
                "required": [
                    "date",
                    "key"
                ],
                "type": "object"
            },
            "type": "array"
        },
        "name": {
            "description": "Human-readable name of the issuing entity",
            "type": "string"
        },
        "revocationKeys": {
            "description": "list of revocation keys, listed in descending date order (most recent first). V1.2 changes: renamed from revocation_key, added optional invalidated field.",
            "items": {
                "additionalProperties": false,
                "properties": {
                    "date": {
                        "_format": "date-time",
                        "description": "ISO-8601 formatted date time the key was activated.",
                        "type": "string"
                    },
                    "invalidated": {
                        "_format": "date-time",
                        "description": "Optional ISO-8601 formatted date time the key was invalidated.",
                        "type": "string"
                    },
                    "key": {
                        "description": "Bitcoin address (compressed public key, usually 24 characters) that the issuer uses to revoke the certificates.",
                        "type": "string"
                    }
                },
                "required": [
                    "date",
                    "key"
                ],
                "type": "object"
            },
            "type": "array"
        },
        "url": {
            "_format": "uri",
            "description": "The URL where the issuer's certificates can be found",
            "type": "string"
        }
    },
    "required": [
        "issuerKeys",
        "revocationKeys",
        "id",
        "name",
        "email",
        "url",
        "introductionURL",
        "image"
    ],
    "type": "object"
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "title": "MerkleProof2017 schema",
    "description": "An extension that allows an issuer to issue an Open Badge on the blockchain and provide proof of inclusion in a blockchain transaction. This uses the Chainpoint v2.0 specification: https://chainpoint.org/",
    "type": "object",
    "definitions": {
        "JsonLdType": {
            "description": "A type or an array of types defined in a JSON-LD context file.",
            "oneOf": [
                {
                    "type": "string"
                },
                {
                    "type": "array",
                    "items": {
                        "type": "string"
                    }
                }
            ]
        }
    },
    "properties": {
        "type": {
            "$ref": "#/definitions/JsonLdType"
        },
        "merkleRoot": {
            "type": "string"
        },
        "targetHash": {
            "type": "string"
        },
        "proof": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "right": {
                        "type": "string"
                    },
                    "left": {
                        "type": "string"
                    }
                }
            }
        },
        "anchors": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "sourceId": {
                        "type": "string"
                    },
                    "type": {
                        "type": "string"
                    }
                }
            }
        }
    },
    "required": [
        "type",
        "merkleRoot",
        "targetHash",
        "proof",
        "anchors"
    ]
}

